/// <summary>
/// Gets or sets the from date.
/// </summary>
/// <param name="_salesAgreementId">
/// The agreement id.
/// </param>
/// <returns>
/// The value of salesAgreementId.
/// </returns>
[
    DataMemberAttribute(identifierStr(SalesAgreementId)),
    SysOperationLabelAttribute(literalstr("Agreement Id")),
    SysOperationHelpTextAttribute(literalstr("SalesAgreement Id"))
]
public SalesAgreementId parmSalesAgreementId(SalesAgreementId _salesAgreementId = salesAgreementId)
{
    salesAgreementId = _salesAgreementId;
    return salesAgreementId;
}
